use vstd::prelude::*;

#[verifier::inline]
spec fn unwrap_or(a: Option<int>, b: int) -> int {
    match a {
        Some(x) => x,
        None => b,
    }
}

spec fn f_quant(opt: Option<int>, opt2: Option<int>) -> bool {
    forall |s: int| {
        match opt {
            Some(x) => {
                unwrap_or(opt2, s) == x
            },
            None => { false }
        }
    }
}
